import{_ as t,c as r,m as a,a as o,t as i,a5 as s,o as d}from"./chunks/framework.DwbewbAn.js";const D=JSON.parse('{"title":"mysql 事务详解","description":"","frontmatter":{"title":"mysql 事务详解"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/事务/事务详解.md","filePath":"packages/doc/src/数据库/Mysql/基础/事务/事务详解.md","lastUpdated":1711622925000}'),l={name:"doc/数据库/Mysql/基础/事务/事务详解.md"},n={id:"frontmatter-title",tabindex:"-1"},c=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=s('<h2 id="什么是事务" tabindex="-1">什么是事务 <a class="header-anchor" href="#什么是事务" aria-label="Permalink to &quot;什么是事务&quot;">​</a></h2><p>事务就是一组DML语句组成，这些语句在逻辑上存在相关性，这一组DML语句要么全部成功，要么全部失败，是一个整体。</p><h2 id="acid-特性" tabindex="-1">ACID 特性 <a class="header-anchor" href="#acid-特性" aria-label="Permalink to &quot;ACID 特性&quot;">​</a></h2><h2 id="隔离级别" tabindex="-1">隔离级别 <a class="header-anchor" href="#隔离级别" aria-label="Permalink to &quot;隔离级别&quot;">​</a></h2><h2 id="_1-事务id生成时机" tabindex="-1">1.事务ID生成时机 <a class="header-anchor" href="#_1-事务id生成时机" aria-label="Permalink to &quot;1.事务ID生成时机&quot;">​</a></h2><p>1.只读事务</p><p>只读事务不能对普通表进行增删改操作，但可以针对临时表做增删改操作。此处的临时表不是执行计划中的临时表</p><p>时机：只在第一次对临时表进行增删改操作才会分配。</p><p>2.读写事务</p><p>时机：只在第一次对表进行增删改操作才会分配，包括对临时表的操作。</p><h2 id="_2-事务id如何形成" tabindex="-1">2.事务ID如何形成 <a class="header-anchor" href="#_2-事务id如何形成" aria-label="Permalink to &quot;2.事务ID如何形成&quot;">​</a></h2><p>服务器维护一个全局变量，假设是x</p><p>1.分配事务ID的时候，分配x,之后x+1</p><p>2.每当x变为256倍数的时候会把值刷到系统表空间的页号为5的MAX TRX ID处，占8个字节</p><p>3.下一次系统启动，将该值加载到内存，再加上256赋值给x,非正常关机的话这个值可能大于MAX TRX ID，最多大256，</p><p>保证不重复</p><p>脏读、不可重复读、幻读 脏读是指在一个事务处理过程里读取了另一个未提交的事务中的数据。 不可重复读是指在对于数据库中的某行记录，一个事务范围内多次查询却返回了不同的数据值，这是由于在查询间隔，另一个事务修改了数据并提交了。 幻读是当某个事务在读取某个范围内的记录时，另外一个事务又在该范围内插入了新的记录，当之前的事务再次读取该范围的记录时，会产生幻行，就像产生幻觉一样，这就是发生了幻读。</p>',17);function h(e,_,m,f,q,u){return d(),r("div",null,[a("h1",n,[o(i(e.$frontmatter.title)+" ",1),c]),p])}const b=t(l,[["render",h]]);export{D as __pageData,b as default};
